    if (!apiKey) {
      throw new HttpException(
        'PREMBLY_API_KEY environment variable is not set',
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
    }

    if (!appId) {
      throw new HttpException(
        'PREMBLY_APP_ID environment variable is not set',
        HttpStatus.INTERNAL_SERVER_ERROR,
      );
    }

    const companyType = dto.companyType ?? 'rc';

    const url = `${this.baseUrl}/identitypass/verification/cac`;

