import {
  Controller,
  Post,
  Req,
  Headers,
  HttpCode,
  HttpStatus,
  UnauthorizedException,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { Request } from 'express';
import { WebhookService } from './webhook.service';

@Controller('webhook')
export class WebhookController {
  private readonly logger = new Logger(WebhookController.name);

  constructor(private readonly webhookService: WebhookService) {}

  /**
   * POST /webhook/prembly
   *
   * Receives Prembly verification status webhooks.
   *
   * Steps:
   *  1. Read the raw body buffer preserved by the rawBody middleware.
   *  2. Verify the HMAC-SHA256 signature in `x-prembly-signature`.
   *  3. Parse and process the JSON payload.
   */
  @Post('prembly')
  @HttpCode(HttpStatus.OK)
  handlePremblyWebhook(
    @Req() req: Request & { rawBody?: Buffer },
    @Headers('x-prembly-signature') signature: string,
  ): { received: boolean } {
    // ── 1. Ensure we have the raw body for signature verification ──────────
    const rawBody: Buffer | undefined = req.rawBody;
    if (!rawBody || rawBody.length === 0) {
      this.logger.warn('Webhook received with empty body');
      throw new BadRequestException('Empty webhook body');
    }

    // ── 2. Verify signature ────────────────────────────────────────────────
    if (!signature) {
      this.logger.warn('Webhook received without x-prembly-signature header');
      throw new UnauthorizedException('Missing x-prembly-signature header');
    }

    const isValid = this.webhookService.verifySignature(rawBody, signature);
    if (!isValid) {
      this.logger.warn('Webhook signature verification failed');
      throw new UnauthorizedException('Invalid webhook signature');
    }

    // ── 3. Parse and process ───────────────────────────────────────────────
    let payload: Record<string, unknown>;
    try {
      payload = JSON.parse(rawBody.toString('utf-8')) as Record<
        string,
        unknown
      >;
    } catch {
      throw new BadRequestException('Webhook body is not valid JSON');
    }

    this.webhookService.processEvent(payload);

    return { received: true };
  }
}

