import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { json, Request, Response, NextFunction } from 'express';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);

  // ── Raw-body capture ─────────────────────────────────────────────────────
  // NestJS uses Express under the hood. We register a custom JSON middleware
  // that stashes the raw Buffer on `req.rawBody` before handing off to the
  // normal JSON body-parser. The WebhookController uses this Buffer to
  // verify the Prembly HMAC-SHA256 signature.
  app.use(
    json({
      verify: (req: Request & { rawBody?: Buffer }, _res: Response, buf: Buffer) => {
        req.rawBody = buf;
      },
    }),
  );

  // ── Global prefix (optional – remove if you prefer bare paths) ───────────
  // app.setGlobalPrefix('api');

  const port = process.env.PORT ?? 3000;
  await app.listen(port);
  console.log(`Application is running on: http://localhost:${port}`);
}

void bootstrap();

