import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { json } from 'express';
import type { Request, Response } from 'express';

async function bootstrap() {
  // Disable the built-in body parser so we can register our own below and
  // have access to the raw Buffer for webhook signature verification.
  const app = await NestFactory.create(AppModule, { bodyParser: false });

  // ── Raw-body capture + JSON parsing ─────────────────────────────────────
  // The `verify` callback runs before the body is parsed; it stashes the raw
  // Buffer on `req.rawBody` so the WebhookController can verify the
  // Prembly HMAC-SHA256 signature without re-reading the stream.
  app.use(
    json({
      verify: (
        req: Request & { rawBody?: Buffer },
        _res: Response,
        buf: Buffer,
      ) => {
        req.rawBody = buf;
      },
    }),
  );

  // ── Global prefix (optional – remove if you prefer bare paths) ───────────
  // app.setGlobalPrefix('api');

  const port = process.env.PORT ?? 3000;
  await app.listen(port);
  console.log(`Application is running on: http://localhost:${port}`);
}

void bootstrap();

